    }
    players(session: $session, format: $format, current: null, active: null) {
      id
      team {
        id
        name
        number
        active
        __typename
      }
      ... on MastersPlayer {
        nineOnSnaps
        eightOnBreaks
        nineBallBreakAndRuns
        eightBallBreakAndRuns
        nineBallMiniSlams
        eightBallMiniSlams
        mastersNineBallWins
        mastersEightBallWins
        matchesWon
        matchesPlayed
        __typename
      }
      ... on NineBallPlayer {
        pa
        ppm
        matchesWon
        matchesPlayed
        miniSlams
        nineBallBreakAndRuns
        nineBallMatchPointsEarned
        nineOnSnaps
        skunks
        __typename
      }
      ... on EightBallPlayer {
        pa
        ppm
        eightBallMatchPointsEarned
        matchesWon
        matchesPlayed
        eightBallBreakAndRuns
        eightOnBreaks
        miniSlams
        rackless
        __typename
      }
      __typename
    }
    __typename
  }
}
"}]

